import React from 'react';
import './news.css';
import Image from './phonk_wallpaper.jpg';


function NewsPage() {
  return(
  <div id="content">
      <div id="news_card">
        <p id="news_card_text">тут типа свежие новости</p>
        <img src={Image} alt="Ну нету авы, я что сделаю!" id="news_card_img"></img>
      </div>
      <div id="news_card">
        <p id="news_card_text">тут типа тоже какие то новости</p>
        <img src={Image} alt="Ну нету авы, я что сделаю!" id="news_card_img"></img>
      </div>
  </div>
  )
}

export default NewsPage;
